// Appends a dated entry to CHANGELOG.md summarizing commits since the last
// run, using the commit SHA recorded in the file's marker comment as the
// starting point. Run by .github/workflows/changelog.yml on every push to
// main — the changelog can't go stale because it's regenerated from git log
// on every push, not hand-maintained.
//
// Safe to run locally too: `node .github/scripts/update-changelog.mjs`
// (writes CHANGELOG.md, doesn't commit or push anything itself).

import { execSync } from "node:child_process";
import { readFileSync, writeFileSync, existsSync } from "node:fs";

const CHANGELOG_PATH = "CHANGELOG.md";
const MARKER_RE = /<!-- changelog-last-sha: ([0-9a-f]{7,40}) -->/;
// First-ever run (no marker yet): seed from a bounded recent window rather
// than the entire repo history.
const INITIAL_LOOKBACK = 15;

function sh(cmd) {
  return execSync(cmd, { encoding: "utf8" }).trim();
}

const headSha = sh("git rev-parse HEAD");
const headShort = sh("git rev-parse --short HEAD");

let existing = existsSync(CHANGELOG_PATH) ? readFileSync(CHANGELOG_PATH, "utf8") : "";
const marker = existing.match(MARKER_RE);
const range = marker ? `${marker[1]}..HEAD` : `-n ${INITIAL_LOOKBACK}`;

// %s = subject, %h = short hash, %an = author name. One commit per line;
// skip the changelog bot's own prior commits and merge commits (no useful
// summary in a merge subject) so the log doesn't self-reference.
const rawLog = sh(
  `git log ${range} --no-merges --pretty=format:"%h|%an|%s"`
);

if (marker && marker[1] === headSha) {
  console.log("No new commits since last changelog entry — nothing to do.");
  process.exit(0);
}

const lines = rawLog
  .split("\n")
  .filter(Boolean)
  .filter((l) => !/chore: update changelog/i.test(l));

if (lines.length === 0) {
  console.log("No non-bot commits in range — nothing to do.");
  process.exit(0);
}

const entries = lines.map((l) => {
  const [hash, author, ...rest] = l.split("|");
  const subject = rest.join("|");
  return `- ${subject} (${hash}, ${author})`;
});

const today = new Date().toISOString().slice(0, 10);
const section = `## ${today}\n\n${entries.join("\n")}\n`;

// Strip any previous marker line before re-inserting it at the top.
const body = existing.replace(MARKER_RE, "").replace(/^# Changelog\n+/, "").trim();

const out =
  `# Changelog\n\n` +
  `<!-- changelog-last-sha: ${headSha} -->\n` +
  `<!-- Auto-generated by .github/workflows/changelog.yml from git log on every push to main. Do not hand-edit above this line's content will be regenerated — new entries are prepended, nothing is removed automatically. -->\n\n` +
  section +
  (body ? `\n${body}\n` : "");

writeFileSync(CHANGELOG_PATH, out);
console.log(`Wrote ${entries.length} entr${entries.length === 1 ? "y" : "ies"} for ${today} (up to ${headShort}).`);
